import React, { useEffect, useState } from "react"

const paymentPlans = [{
    planTitle: '24x',
    planDuration: '24',
    id: 'plan-1'
},
{
    planTitle: '12x',
    planDuration: '12',
    id: 'plan-2'
},
{
    planTitle: '6x',
    planDuration: '6',
    id: 'plan-3'
},
{
    planTitle: '3x',
    planDuration: '3',
    id: 'plan-4'
}
]

const amount = 24435

function getDateLabel(inputDate) {
    const today = new Date()
    let tomm = new Date()
    tomm = tomm.setDate(tomm.getDate(tomm) + 1)
    today.setHours(0, 0, 0, 0)
    tomm.setHours(0, 0, 0, 0)
    if (inputDate.getTime() === today.getTime()) {
        return 'Today'
    } else if (inputDate.getTime() === tomm.getTime()) {
        return 'Tommorrow'
    } else {
        return inputDate.toLocaleDateString('en-GB', { month: 'short', day: 'numeric', year: 'numeric' })
    }
}
async function calculateInstallments(planDuration, totalAmount) {
    const data = await new Promise((res) => {
        const startDate = new Date()
        const calculatedInstallment = Number((Number(totalAmount) / Number(planDuration)).toFixed(2))
        const arr = Array.from({ length: planDuration }, (_, i) => {
            const date = new Date(startDate)
            date.setMonth(date.getMonth() + i)
            return { dueDate: date.toISOString().slice(0, 10), dueDateLabel: getDateLabel(date), dueAmt: calculatedInstallment }
        })
        setTimeout(() => {
            res([...arr])
        }, 1000)
    })
    return data
}

export async function getTotalAmount() {
    return new Promise((resolve) => {
        setTimeout(() => {
            return resolve(amount)
        }, 500)
    })
}

export async function getPlansData() {
    return new Promise((resolve, reject) => {
        setTimeout(() => {
            return resolve(paymentPlans)
        }, 500)
    })
}

export async function getInstallments(planDuration, totalAmount) {
    return new Promise((resolve, reject) => {
        setTimeout(() => {
            return resolve(calculateInstallments(planDuration, totalAmount))
        }, 500)
    })
}

function useData(fn, options = { disableInitialLoad: false }) {
    const [resp, setResp] = useState({
        data: null,
        loading: false,
        error: null
    })

    async function fetchData(fn) {
        setResp((prev) => {
            return {
                ...prev,
                loading: true
            }
        })
        try {
            const result = await fn()
            setResp((prev) => {
                return {
                    ...prev,
                    data: result
                }
            })
        } catch (err) {
            setResp((prev) => {
                return {
                    ...prev,
                    error: { message: 'Following error occured:', log: err }
                }
            })
        } finally {
            setResp((prev) => {
                return {
                    ...prev,
                    loading: false
                }
            })
        }
    }

    function refetch(...args) {
        fetchData(...args)
    }

    useEffect(() => {
        if (!options.disableInitialLoad && fn) {
            fetchData(fn)
        }
    }, [])

    return { refetch, ...resp }
}

export default useData
